    'type': 'object',
    'properties': {
        'actionGroup': {'type': 'string'},
        'apiPath': {'type': 'string'},
        'httpStatusCode': {'type': 'integer'},
        'responseBody': {'type': 'object'}
    },
    'required': ['actionGroup', 'apiPath', 'httpStatusCode']
}

def validate_lambda_response(response_event):
    try:
        lambda_output = json.loads(response_event.get('completion', ''))
        if not all(key in lambda_output for key in ['actionGroup', 'apiPath', 'httpStatusCode']):
            return {'drift_detected': True, 'issue': 'missing_required_fields'}
        return {'drift_detected': False}
    except (json.JSONDecodeError, KeyError) as e:
        return {'drift_detected': True, 'issue': f'parse_error: {str(e)}'}

def analyze_kb_retrieval(response):
    retrievals = response.get('retrievalResults', [])
    domain_keywords = {'contract', 'invoice', 'customer', 'policy', 'compliance'}

    keyword_coverage = 0
    for doc in retrievals:
        doc_text = doc.get('content', {}).get('text', '')
        covered = sum(1 for kw in domain_keywords if kw in doc_text.lower())
        keyword_coverage += covered

    coverage_score = keyword_coverage / len(domain_keywords)
    return {
        'drift_detected': coverage_score < 0.3,
        'coverage_score': coverage_score,
        'retrieved_docs': len(retrievals)
    }

import re

def detect_policy_violations(agent_response):
    content = agent_response.get('output', {}).get('text', '')

    violations = {
        'pii': bool(re.search(r'\b(?:SSN|credit card|passport)\b', content, re.IGNORECASE)),
        'brand': bool(re.search(r'competitor[\s\w]*name', content, re.IGNORECASE)),
        'speculative': len(re.findall(r'may|might|possibly|probably', content.lower())) > 3
    }

    violation_count = sum(violations.values())
    return {
        'drift_detected': violation_count > 0,
        'violations': violations,
        'violation_count': violation_count
    }

